  json: {
    userId: routerData.userId,
    messageId: routerData.messageId,
    messageType: 'document',
    textContent: routerData.textContent || '',
    caption: routerData.textContent || '',
    mediaUrl: routerData.mediaUrl,
    source: routerData.source,
    timestamp: routerData.timestamp,
    output: geminiOutput,
    analysis: geminiOutput,
    processedText: routerData.textContent || geminiOutput || 'What can you help me with this document?'
  }
};

// Generate deterministic response directly from stored image analysis.
const prepareData = $node['Prepare AI Input'].json || {};
const processData = $node['Process Media Context'].json || {};
const mergeData = $node['Merge Image Analysis'].json || {};

const getText = (value) => {
  if (value === undefined || value === null) return '';
  return String(value).trim();
};

const question = getText(
  processData.originalQuestion ||
  processData.originalCaption ||
  prepareData.question ||
  prepareData.caption ||
  mergeData.caption ||
  'this image'
);

const analysis = getText(
  processData.imageAnalysis ||
  processData.geminiAnalysis ||
  prepareData.imageAnalysis ||
  mergeData.analysis ||
  ''
);

const containsHebrew = (text) => /[\u0590-\u05FF]/.test(text || '');
const useHebrew = containsHebrew(question) || containsHebrew(analysis);

let response;
if (analysis) {
  response = useHebrew
    ? `✅ כן, אני רואה את התמונה ושמתי לב לבאים:\n${analysis}`
    : `✅ Yes, I can see the image. Here is what I observe:\n${analysis}`;
} else {
  response = useHebrew
    ? '✅ כן, קיבלתי את התמונה אך לא נמצא טקסט ניתוח. אנא שלח שוב או הסבר מה תרצה שנבדוק.'
    : '✅ I received your image but the analysis data was empty. Please resend it or tell me what you need help with.';
}

return [{
  json: {
    ...processData,
    ...prepareData,
    output: response,
    responseText: response,
    answeredFromImageAnalysis: analysis.length > 0
  }
}];

// Guardrails: Check video file size
const maxSizeMB = 15;
const payload = $json.payload || {};
const data = payload._data || {};
const videoMsg = data.message ? data.message.videoMessage : null;
const fileSize = videoMsg ? Number(videoMsg.fileLength) : 0;
const fileSizeMB = fileSize / (1024 * 1024);

if (fileSizeMB > maxSizeMB) {
  // Stop execution for this branch
  return [];
}

return [$input.item];

